class Solution {
public:
    int reachNumber(int target) {
        target = abs(target);
        int sum = 0;
        int k = 0;
        while (true) {
            k++;
            sum += k;
            if (sum >= target && (sum - target) % 2 == 0) {
                return k;
            }
        }
    }
};

